	Catalog.SetString(tag_he_x_NoNikud, "MEMO:Yom HaZikaron", "יום הזיכרון לחללי מערכות ישראל. זוכר את אלו שנפלו במלחמת העצמאות ובמלחמות ישראל האחרות. השם המלא של החג הוא “יום הזיכרון לחללי מערכות ישראל ולנפגעי פעולות האיבה״. למרות שיום הזיכרון מצוין בדרך כלל בד' באייר, הוא עשוי להיות מוקדם או להידחות אם קיום היום (או יום העצמאות שבא תמיד אחריו) יתנגש עם השבת")
